('f852587c-880c-4432-8668-ccf11297d869', '4b1f177e-b61b-4721-bb94-10e71dc50c4e', 5, NULL, 'note', 'en', 'Recommended TTS speed: 0.85 to 0.95', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('387ff066-f715-4c5c-b15f-556458b46a79', 'c1e0c406-374b-4a0b-a715-d1d3f57ff41a', 1, NULL, 'text', 'en', 'Good morning everyone.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('76a212a9-1469-4381-abea-3893163ad9c8', 'c1e0c406-374b-4a0b-a715-d1d3f57ff41a', 2, NULL, 'text', 'en', 'Welcome to our company.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('64058d76-6267-4a9b-9cee-9c45b99f7117', 'c1e0c406-374b-4a0b-a715-d1d3f57ff41a', 3, NULL, 'text', 'en', 'My name is [Your Name], and I will be guiding you throughout this internship.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('38afb70d-31f9-4c76-aae7-7a3954d91a15', 'c1e0c406-374b-4a0b-a715-d1d3f57ff41a', 4, NULL, 'text', 'en', 'We are very happy to have you here.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('6950073d-04dd-45cb-a7b1-f7f50499d034', '0891264c-262b-4eb3-851d-ecdb7987ef4e', 1, NULL, 'text', 'en', 'Over the next six weeks, you will rotate through different departments including QC, R&D, production, and warehouse.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('d9c00589-3021-45dc-b2c6-c71cd5a3f647', '0891264c-262b-4eb3-851d-ecdb7987ef4e', 2, NULL, 'text', 'en', 'The goal is to give you real-world experience.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('12ffc4f5-0def-42cc-998f-f63c323b265d', '8a9923f7-8a3d-48b9-8d3a-7567c5a091e1', 1, 'Instructor', 'instructor', 'en', 'Could you briefly introduce yourself?', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('4a7f659c-e6fa-472e-a273-a1b82a5f88d5', '8a9923f7-8a3d-48b9-8d3a-7567c5a091e1', 2, 'Student', 'student', 'en', 'I am majoring in pharmacy.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('68accebe-9cf8-40fa-b819-0d3fe05da613', '8a9923f7-8a3d-48b9-8d3a-7567c5a091e1', 3, 'Instructor', 'instructor', 'en', 'That is great. What are you hoping to learn here?', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('3a7a75af-1d72-4e13-a7c7-117e200c289f', '0a040557-ae37-437e-9598-6d8e9a8521e9', 1, NULL, 'text', 'en', 'This is the Quality Control lab.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('2e1418f7-7465-4296-9711-9f9285fd1e4c', '0a040557-ae37-437e-9598-6d8e9a8521e9', 2, NULL, 'text', 'en', 'Here, we test raw materials, in-process samples, and finished products.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('b4ce8eb2-b900-4f15-9999-48076116e157', '0a040557-ae37-437e-9598-6d8e9a8521e9', 3, NULL, 'text', 'en', 'Accuracy is very important in this lab.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('4d215c08-e84e-42f9-a3af-07837f254a20', '62cb06a6-3b35-4c5a-a4fd-84c93b0bd7ba', 1, NULL, 'text', 'en', 'Let us walk through the process together.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('f74d674d-7e5b-4678-94c1-66ff88b324a2', '62cb06a6-3b35-4c5a-a4fd-84c93b0bd7ba', 2, NULL, 'text', 'en', 'First, calibrate the instrument.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('9de5af28-bd96-4af7-900d-f37f0c9b8768', '62cb06a6-3b35-4c5a-a4fd-84c93b0bd7ba', 3, NULL, 'text', 'en', 'Then measure the sample.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('0dc47f82-83a9-4b90-8508-8771181c59b7', '62cb06a6-3b35-4c5a-a4fd-84c93b0bd7ba', 4, NULL, 'text', 'en', 'Record the results immediately.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('e97d60f3-8f07-4c31-934d-619ab27322e6', 'e8062ecc-bef9-4ed9-b003-59dd2ce3fdaa', 1, 'Student', 'student', 'en', 'Why do we need to calibrate every time?', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('82fc816d-a965-46ee-be70-a1975a760100', 'e8062ecc-bef9-4ed9-b003-59dd2ce3fdaa', 2, 'Instructor', 'instructor', 'en', 'That is a great question. Calibration ensures accuracy. Even small deviations can affect the result.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('19c55db4-066b-435b-a32e-2b7f429e65d8', '6fc14239-378f-4683-b3db-50bea4a8357d', 1, NULL, 'text', 'en', 'This is the R&D lab.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('a6a92c3a-838e-4dd7-a4e6-05917e31ad7e', '6fc14239-378f-4683-b3db-50bea4a8357d', 2, NULL, 'text', 'en', 'We focus on developing new formulations, improving stability, and ensuring product effectiveness.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('aa29863d-df8f-44ee-aa25-ba59fb4d0efa', '5956eaec-ffa4-46bc-820d-25b51e28c401', 1, 'Student', 'student', 'en', 'How do you choose excipients?', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('714f34a1-5865-4f4c-bf8b-fd40deab8a11', '5956eaec-ffa4-46bc-820d-25b51e28c401', 2, 'Instructor', 'instructor', 'en', 'It depends on the formulation goals, such as stability, solubility, and release profile.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('f361bd3f-c8a6-4e4d-90b5-40cc6cd8483a', 'fc26cb77-e632-42b0-a8e5-39b57dda0c9a', 1, NULL, 'text', 'en', 'This is the production area.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('c3f59bdf-4268-4e11-8232-b855c9005f79', 'fc26cb77-e632-42b0-a8e5-39b57dda0c9a', 2, NULL, 'text', 'en', 'Everything here follows GMP regulations.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('ab375745-c6f5-4aa7-81b2-bc0efe96d57a', 'fc26cb77-e632-42b0-a8e5-39b57dda0c9a', 3, NULL, 'text', 'en', 'Please follow all SOPs carefully.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('bea8d7e1-2879-4715-953b-8dbe1397e671', '4c4e41cf-3dcd-49e8-9a58-8ed3bafc7ea4', 1, 'Student', 'student', 'en', 'Why is documentation so detailed?', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('0088d39d-c1ff-4acb-b349-239469d56154', '4c4e41cf-3dcd-49e8-9a58-8ed3bafc7ea4', 2, 'Instructor', 'instructor', 'en', 'Because traceability is critical. We need to track every step in case of issues.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('37239ead-2841-4b22-8b7e-b9caf00c5d35', '551798f1-1440-40e0-a7e5-519451150939', 1, NULL, 'text', 'en', 'This is our warehouse.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('4d20cb4e-9120-4e16-8076-6dafe84d6135', '551798f1-1440-40e0-a7e5-519451150939', 2, NULL, 'text', 'en', 'We store materials under controlled conditions.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('55d90fd9-b367-4e56-aa65-6e96e3d7eeef', '551798f1-1440-40e0-a7e5-519451150939', 3, NULL, 'text', 'en', 'Temperature and humidity are monitored continuously.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('cddc39f8-c4a0-4309-ac2b-d809677ca272', '6eac4f26-e145-4973-8c3b-cb76c4eeb7c9', 1, 'Student', 'student', 'en', 'How do you manage inventory?', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('e05ad828-2cf0-46ea-84ff-0e5155cc76c3', '6eac4f26-e145-4973-8c3b-cb76c4eeb7c9', 2, 'Instructor', 'instructor', 'en', 'We use a digital system to track everything in real time.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('8efb7ca2-5177-4eb9-a076-b059814f6156', '76298872-c07a-42aa-ac5f-367c33fe7de1', 1, NULL, 'text', 'en', 'You will present what you have learned.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('e15493ed-4fba-431c-be0e-5bd1d3b880d5', '76298872-c07a-42aa-ac5f-367c33fe7de1', 2, NULL, 'text', 'en', 'Keep your presentation clear and structured: introduction, process, and conclusion.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('22138ba8-9142-41df-a97c-5cc326dd9c02', '3edaa908-a9d2-4107-ac04-9a77f339818e', 1, 'Instructor', 'instructor', 'en', 'That was a solid presentation.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('37f86c2d-2248-4c52-bb16-5845431a7bd5', '3edaa908-a9d2-4107-ac04-9a77f339818e', 2, 'Instructor', 'instructor', 'en', 'One thing you could improve is explaining this part more clearly.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
('c8700d86-be6b-4403-9c92-1ae1b2fc2542', '3edaa908-a9d2-4107-ac04-9a77f339818e', 3, 'Instructor', 'instructor', 'en', 'But overall, great job.', TRUE, '2026-04-22T08:48:20.56321+00:00'),
